import React, { useState } from 'react';
import axios from 'axios';

function Reporte() {
    // 1. VARIABLES DE ESTADO (La memoria de React)
    const [idBanner, setIdBanner] = useState(''); // Guarda lo que el usuario escribe
    const [reporte, setReporte] = useState(null); // Guarda la respuesta de la API
    const [error, setError] = useState('');       // Guarda los mensajes de error

    // 2. FUNCIÓN PARA LLAMAR A LA API
    const buscarAlumno = async () => {
        try {
            setError(''); // Limpiamos errores previos
            setReporte(null); // Limpiamos datos previos

            const respuesta = await axios.get(`http://localhost:5286/api/Reporte/calificacionesFinales/${idBanner}`);
            
            // Si la API responde OK (200), guardamos los datos en la memoria
            setReporte(respuesta.data);
        } catch (err) {
            // Si la API responde 404 (Not Found), atrapamos el error
            setError('No se encontró el alumno o aún no tiene notas.');
        }
    };

    return (
        <div style={{ padding: '40px', fontFamily: 'Arial, sans-serif' }}>
            <h2>Calculadora de Nota Minima Progreso 3</h2>
            
            <input
                type="text"
                placeholder="Ingresa tu ID Banner (Ej: 17075)"
                value={idBanner}
                onChange={(e) => setIdBanner(e.target.value)}
                style={{ padding: '10px', fontSize: '16px', marginRight: '10px' }}
            />
            <button onClick={buscarAlumno} style={{ padding: '10px 20px', fontSize: '16px', cursor: 'pointer' }}>
                Consultar
            </button>

            {/* Mensaje de error en rojo si algo falla */}
            {error && <p style={{ color: 'red', marginTop: '20px' }}>{error}</p>}

            {/* Si existe el reporte, dibujamos los resultados */}
            {reporte && (
                <div style={{ marginTop: '30px', border: '1px solid #ccc', padding: '20px', borderRadius: '8px', maxWidth: '400px' }}>
                    <h3>Resultados de: {reporte.nombreAlumno}</h3>
                    <p><strong>Nota P1 (25%):</strong> {reporte.notaFinalP1}</p>
                    <p><strong>Nota P2 (35%):</strong> {reporte.notaFinalP2}</p>
                    <hr />
                    <p><strong>Acumulado Actual:</strong> {reporte.acumulado} / 6.0</p>
                    <h3 style={{ color: '#0056b3' }}>
                        Necesitas en P3: {reporte.notaNecesitada}
                    </h3>
                </div>
            )}
        </div>
    );
}

export default Reporte;
